// // This module selects between two 32-bit inputs based on the 1-bit select signal.
// If the select signal is 0, the output is the first input; otherwise, it's the second input.
module mux2to1_32(
    input wire sel,
    input wire [31:0] a,
    input wire [31:0] b,
    output reg [31:0] o
);

always @(*)
    if(sel == 0)
        o <= a;
    else
        o <= b;

endmodule
